update tbl_news_reply
set reply_status = 'deleted',
    updated_datetime = current_timestamp
where id = #{id}
  and member_id = #{memberId}
  and reply_status = 'active'

update tbl_news_reply
set content = #{content},
    updated_datetime = current_timestamp
where id = #{id}
  and member_id = #{memberId}
  and reply_status = 'active'
